{
  "name": "Maryland Durable Medical Equipment Reuse Program (DME)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available regardless of income",
    "asset_limits": "No asset limits or tests mentioned",
    "other_requirements": ["Maryland resident", "Any illness, injury, or disability", "For complex equipment: Form Parts B and C completed by healthcare provider (Physician, Physical Therapist, Occupational Therapist, Physician’s Assistant, or Nurse Practitioner)"]
  },
  "benefits": {
    "type": "in_kind",
    "value": "Free durable medical equipment including: Basic - Canes, crutches, walkers, rollators, shower chairs, tub transfer benches, bedside commodes, toilet safety rails, transfer boards. Complex (requires provider form) - Manual wheelchairs, transport wheelchairs, knee scooters, semi/electric home hospital beds, patient (Hoyer) lifts, trapeze bars, power wheelchairs (PT/OT only), power scooters (PT/OT only), upright rollators, rolling shower chairs. Other items like bedrails, over bed tables, toilet risers may be available. Equipment is sanitized, repaired, donated stock; kept permanently by recipient",
    "varies_by": "equipment_type"
  },
  "application": {
    "methods": ["Online: https://onestop.md.gov/forms/basic-durable-medical-equipment-request-form-618bcb19e9b09f023f463960 (Basic DME Request Form; use Complex Request Form for advanced items)", "Phone: 240-230-8000 or (410)-767-1100 / 1-800-243-3425", "Email: dme.mdoa@maryland.gov", "In-person pickup by appointment at multiple state locations (e.g., 11701 Crain Highway, Cheltenham, MD 20623); no home delivery"],
    "processing_time": "After submission, form goes 'In-Review'; staff contact via preferred method to confirm stock and schedule pickup (timeline not specified)",
    "waitlist": "No waitlist mentioned; depends on equipment availability in stock",
    "forms": ["Basic DME Request Form (online via OneStop)", "Complex Request Form (Parts B and C by provider for advanced items)"],
    "documents": ["For basic: Complete online form with required fields (*). For complex: Provider-completed Parts B and C. No prescription or insurance needed"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Maryland residents only",
    "regional_variations": "Pickup by appointment at multiple delivery/pickup sites around the state; no regional differences in eligibility or benefits specified; many drop-off points across Maryland",
    "offices_or_providers": ["Main: 11701 Crain Highway, Cheltenham, MD 20623", "Multiple pickup sites statewide (call to confirm)"]
  },
  "official_source": "https://aging.maryland.gov/pages/DME.aspx",
  "gotchas": ["No home delivery; must pickup by appointment", "Complex items require healthcare provider to complete form parts", "Availability depends on donated stock - call ahead to verify", "All required form fields (*) must be filled or request is voided", "Encouraged but not required to donate back when no longer needed"],
  "data_shape_notes": "No income/age/asset tests; free to all MD residents with need; two-tier equipment (basic vs complex with provider form); stock-dependent availability; statewide with regional pickup sites only"
}

{
  "name": "Low-Income Home Energy Assistance Program (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "FY26 income guidelines (at or below 150% of Federal Poverty Guidelines, gross monthly income before taxes): 1: $2,608; 2: $3,525; 3: $4,441; 4: $5,358; 5: $6,275; 6: $7,191; 7: $8,108; 8: $9,025; 9: $9,942; 10: $10,859; 11+: Contact local OHEP office. Households receiving SNAP or TCA are categorically eligible without income proof or full application.[4][5]",
    "asset_limits": "No asset limit applies.[1]",
    "other_requirements": ["Household includes everyone at the address covered by the same utility bill, even if not sharing expenses.[1]", "Income-based only; no turn-off notice required.[4][5][7]"]
  },
  "benefits": {
    "type": "financial",
    "value": "Maryland Energy Assistance Program (MEAP): Heating assistance max $750, min $25; Crisis assistance (year-round) winter max $600 (summer cooling not available). Payments made directly to utility/fuel supplier. Additional programs: EUSP (electric grant, once per July-June year); USPP (turn-off protection during heating season with budget billing).[1][7]",
    "varies_by": "household_size|priority_tier"
  },
  "application": {
    "methods": ["Online: https://marylandbenefits.gov or https://mydhrbenefits.dhr.state.md.us[5][6]", "Phone: 1-800-332-6347 (request application or assistance)[4][5][6]", "Mail: Submit completed DHS-FIA-9780-OHEP-Application for Energy Assistance with documents[4]", "In-person: Local OHEP/energy office or home visits for seniors/disabled/homebound[5]"],
    "processing_time": "Not specified; apply early as funding limited and may close when funds exhausted[1]",
    "waitlist": "No waitlist mentioned; first-come, first-served until funds run out[1][6]",
    "forms": ["DHS-FIA-9780-OHEP-Application for Energy Assistance[4]"],
    "documents": ["Photo ID (driver's license, state ID, passport, etc.; for age 62+/disabled/homebound: birth cert/Medicaid/Medicare card or SSN document, no photo ID required)[2]", "Proof of residency[4]", "SSN for all household members (cards or documents)[2][4]", "Proof of gross household income last 30 days[4]", "Most recent utility bill or termination notice (if applicable)[4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide through local OHEP offices",
    "regional_variations": "Administered via local OHEP offices/providers; contact local office for 11+ household incomes or specifics; some regional providers like Dollar Energy for MEAP[3][4]",
    "offices_or_providers": ["Local OHEP offices (find via 1-800-332-6347 or state site); examples include Choptank Electric for certain areas[5]"]
  },
  "official_source": "https://dhs.maryland.gov/office-of-home-energy-programs/[4][7]",
  "gotchas": ["Funding limited; apply early as applications may close when funds exhausted, even if program year-round[1][5]", "Household counts all at address on utility bill, unlike SNAP[1]", "SNAP/TCA recipients auto-eligible post-redetermination, no app needed[5]", "Must reapply annually[6]", "EUSP once per program year (July-June); USPP requires budget billing adherence[7]", "No cooling assistance except crisis[1]"],
  "data_shape_notes": "Administered via OHEP as MEAP (heating) + EUSP (electric) + crisis; year-round but heating-focused fall/winter; categorical eligibility for SNAP/TCA; varies by fuel type, income, size; local offices handle large households"
}

{
  "name": "Maryland Weatherization Assistance Program",
  "eligibility": {
    "age": null,
    "income_limits": "Statewide DOE WAP limits (updated 2/11/2026): max of 60% State Median Income (SMI) or 200% Federal Poverty Level (FPL), whichever is higher. Table for HH size 1: $48,085 (60% SMI); HH size 2: $62,880 (60% SMI). Full table not completely listed in sources but follows this pattern. Automatic eligibility if receiving: OHEP Utility Bill Pay Assistance, SNAP, TANF, SSI, HUD housing. Not automatic: Fuel Fund, Medicaid, etc. Priority for elderly (60+), disabled, families with children, high energy users/burden.[1][2][3]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Homeowners must prove ownership; renters eligible if landlord agrees.[3]", "Cannot have received weatherization services in last 12 months via WAP or similar.[2]", "Household must meet income guidelines; preference for elderly (60+), disabled, children under 5, high energy use.[1][2][4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free in-home energy efficiency upgrades including: insulation (attic, floors, walls), blower door air infiltration reduction, hot water system improvements, lighting retrofits, furnace clean/tune/safety repairs/replacement/burner retrofit, health/safety items. Reduces energy costs by avg 30-35%. No specific dollar cap per home; based on assessment.[2][3]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: 844-400-3423 or 1-800-756-0119 (Office of Energy Efficiency, DHCD); 1-855-583-8976 (OHEP help); 240-777-4450 (EmPOWER MD).[2][3][7]", "DHCD application (screens for multiple programs); MCEEP Application (Montgomery).[3][7]", "Local agencies for assessment after eligibility."],
    "processing_time": "Not specified; local agency schedules energy assessment after eligibility determination.[3]",
    "waitlist": "Not mentioned; priority given to elderly/disabled/families/high energy users, implying possible delays.[1]",
    "forms": ["Office of Home Energy Programs (OHEP) or DHCD application; MCEEP Application.[3][7]"],
    "documents": ["Proof of income/household size; proof of homeownership (for owners); utility bills (for energy burden); proof of participation in auto-eligible programs (e.g., SNAP award letter).[1][2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Statewide for income-eligible MD residents; some local variations (e.g., Frederick/Carroll/Washington Counties crisis program; Prince George's specific prefs).[2][4]",
    "regional_variations": "Administered via local agencies/nonprofits (e.g., Community Action Council in Howard; Frederick HHS); income thresholds may appear higher locally (e.g., Frederick HH1 $68,500) but statewide DOE limits apply; building eligibility (e.g., ≤4 units).[4][6]",
    "offices_or_providers": ["MD DHCD Office of Energy Efficiency; local subgrantees like Prince George's Housing, Frederick HHS, Community Action Council.[1][2][4][6]"]
  },
  "official_source": "https://dhcd.maryland.gov/Energy-Home-Repair/pages/homeowner-grants/wap.aspx",
  "gotchas": ["Not auto-eligible from Medicaid, Fuel Fund, or DHCD rehab programs—must meet income directly.[1]", "Renters need landlord approval; no repeat services within 12 months.[2][3]", "Priority tiers mean elderly may wait less, but high demand possible; prove ownership strictly for homeowners.[1][2]", "Commercial spaces ineligible; multi-unit buildings limited (≤4 units standard).[4]"],
  "data_shape_notes": "Statewide with local agency delivery and priority tiers; income max(60% SMI, 200% FPL) auto-eligible via specific programs only; no asset test; benefits via professional assessment not fixed dollar."
}

{
  "name": "Home Delivered Meals",
  "eligibility": {
    "age": 60,
    "income_limits": "No statewide income limits specified; some providers like Meals on Wheels of Central Maryland assess fees based on reported monthly income and expenses via telephone intake, but documentation not required[4]. Medicaid waiver programs (CFC, HCBOW, ICS) require financial eligibility for institutional level of care, but specific dollar amounts not listed[3].",
    "asset_limits": "No asset limits or details on countable/exempt assets mentioned across sources.",
    "other_requirements": ["Homebound (unable to leave home without assistance or shop/cook for self)[1][2][7]", "No caregiver to help with meal preparation[1]", "Live within delivery area of local provider[1]", "For Medicaid waivers: Medically necessary, pre-authorized in service plan, prevents institutionalization; cannot require assistance to warm/feed/clean up meal[3]", "Some programs require referral (e.g., healthcare provider for Moveable Feast)[6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Nutritionally balanced meals (at least 1/3 RDA/DRI, physician-certified menus); typically 1 hot meal/day M-F plus cold meal or frozen (5/week); weekly delivery of 10 frozen medically tailored entrees + produce for some; friendly volunteer visit; special diets accommodated; max 14/week in Medicaid waivers[2][3][6][7]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Phone: Varies by region/provider, e.g., Meals on Wheels Central MD 410-558-0923[4], Anne Arundel 410-222-4257[7]", "Online: Meals on Wheels Central MD application form at mealsonwheelsmd.org/meal-connect/apply/[4]", "Referral: Required for some (e.g., provider referral to Moveable Feast)[6]", "Contact local Area Agency on Aging via Maryland Department of Aging site aging.maryland.gov for county-specific[8]"],
    "processing_time": "Usually within a few days (Anne Arundel)[7]; telephone intake follow-up for Central MD[4]",
    "waitlist": "Not mentioned; varies by local agency capacity[1]",
    "forms": ["Application for Service (Meals on Wheels Central MD online/telephone)[4]"],
    "documents": ["No documentation required but prepare: monthly income/expenses (all sources), medical info (allergies, conditions, prescriptions, doctors, insurance, hospitalizations), emergency contacts, adaptive equipment[1][4]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Administered locally via Area Agencies on Aging and county providers; must live in service area",
    "regional_variations": "Varies by county/provider: e.g., St. Mary's (fresh M-F + weekly frozen)[2]; Anne Arundel (hot+cold M-F, quick start)[7]; Central MD (income-assessed fees)[4]; Baltimore Moveable Feast (10 frozen entrees/week + produce, referral-only for specific illnesses)[6]; different offices per county listed at aging.maryland.gov[8]",
    "offices_or_providers": ["Anne Arundel: 410-222-4257[7]", "St. Mary's County[2]", "Meals on Wheels Central MD: 410-558-0923[4]", "Moveable Feast Baltimore[6]", "County contacts via aging.maryland.gov[8]"]
  },
  "official_source": "https://aging.maryland.gov/pages/nutrition.aspx",
  "gotchas": ["Not a single statewide program—contact local Area Agency on Aging for your county; some charge sliding-scale fees based on income (e.g., Central MD); spouses/dependents may qualify but check locally; disabled non-seniors may be ineligible or pay (e.g., quadriplegic son disqualified)[1][4]; Medicaid waivers limit to 14/week, no assist with warming/feeding; referral required for specialized providers[3][6]"],
  "data_shape_notes": "Decentralized by county/provider with unique eligibility/providers/wait times; no uniform income table; often no caregiver + homebound core req; some fee-based or referral-only"
}

