{
  "name": "Senior Legal Assistance Program (Sixty Plus Legal Program)",
  "eligibility": {
    "age": 60,
    "income_limits": "Annual income must meet Maryland Legal Services Corporation (MLSC) guidelines, typically 50% of Maryland median income or up to 125% of federal poverty level depending on provider. Example from 2012-2013: $26,521 individual, $34,681 couple. Recent MVLS guidelines (50% median): Family of 1: $39,125/year; 2: $52,875; 3: $66,625; 4: $80,375; 5: $94,125; 6: $107,875. Senior Legal Helpline up to 500% FPL. Exact current limits confirmed via local AAA[1][2][3][4][9].",
    "asset_limits": "Assets considered (property, vehicles, financial accounts); exceptions for medical expenses or other factors per MLSC guidelines. No fixed dollar limits specified statewide[3].",
    "other_requirements": ["Maryland resident", "Priority for greatest economic or social need", "Focus on civil legal issues like income maintenance, public benefits, housing, abuse"]
  },
  "benefits": {
    "type": "service",
    "value": "Free or low-cost legal advice, counseling, and representation by local attorneys or law centers. Priority areas: income maintenance, nutrition, public/disability benefits, health care, protective services, abuse, housing, utilities, consumer protection, employment, age discrimination, advocacy for institutionalized persons. No cost for priority issues; low-cost via private attorneys for others[1][2][5][6].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging (AAA) Maryland Access Point (MAP) - find via aging.maryland.gov", "Senior Legal Helpline: 1-800-896-4213 (Mon-Fri 9am-4pm)", "Eldercare Locator: 1-800-677-1116 or eldercare.acl.gov", "Local examples: St. Mary's (301-475-4200 ext. 1064), Baltimore Senior Legal Services (410-396-1322)", "In-person/mail via local AAA or contracted providers like Maryland Legal Aid"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": ["No specific statewide form; intake via phone or local AAA"],
    "documents": ["Proof of age, income, assets, residency; case details (e.g., benefit denial letters, housing docs)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services via local Area Agencies on Aging (AAAs); some counties contract specific providers (e.g., St. Mary's with Maryland Legal Aid, Baltimore with Senior Legal Services)",
    "regional_variations": "Delivered through 19 AAAs with local attorneys/law centers; providers differ by county (e.g., MVLS excludes some counties like Montgomery, Prince George's); wait times/case types may vary[2][3][5][6][10].",
    "offices_or_providers": ["Local AAAs/MAP sites statewide", "Maryland Legal Aid", "MVLS", "Baltimore Senior Legal Services"]
  },
  "official_source": "https://aging.maryland.gov/pages/senior-legal-assistance.aspx",
  "gotchas": ["Income based on MLSC guidelines which update yearly - verify current via AAA; free only for priority issues, low-cost otherwise; preference for greatest need may limit access; some counties have specialized exclusions/providers; not full representation always - may be advice/referral only[1][2][3][9]."],
  "data_shape_notes": "Decentralized via 19 local AAAs with contracted providers; income follows variable MLSC guidelines (50% median or 125% FPL); priority tier determines free vs low-cost; regional provider differences"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; this is not a financial assistance program. Note: Search result [1] confuses it with Medicaid eligibility, which is separate and requires income/resources tests for those 65+ or disabled (specific limits not detailed here).[1]",
    "asset_limits": "No asset limits; advocacy services are free and available to all residents regardless of finances.[3][4]",
    "other_requirements": ["Resident (or prospective resident) of a nursing home or assisted living facility in Maryland.", "Services are resident-directed and require resident consent (or resident representative if applicable).", "Available to residents, families, friends, facility staff, or community members with concerns about resident rights, care, or quality of life.[3][5][6]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy for health, safety, well-being, and rights; complaint investigation and resolution (resolves ~3,300 complaints/year); regular facility visits (~7,000/year across 1,850 facilities); education on rights and aging issues; information/referral; consultation; policy advocacy; monitoring conditions; support until disputes resolved. Free and confidential. No dollar amounts, hours, or tiers specified.[3][4][6][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Contact local LTC Ombudsman program via 19 Local Programs at Area Agencies on Aging (regions served statewide).", "State Office: Maryland Department of Aging (website: https://aging.maryland.gov/pages/state-long-term-care-ombudsman.aspx).[3]", "Examples: Howard County - Phone: 410-313-6423, Email: LTCOmbudsman@howardcountymd.gov.[7]", "Montgomery County - Phone for related info: 240-777-3005 (Medicaid confusion noted).[1]", "No formal application form; services start with contacting Ombudsman to discuss concerns (consent obtained as needed).[2][3]"],
    "processing_time": "Immediate response for consultation; complaint resolution varies by case (no fixed timeline specified).[3][4]",
    "waitlist": null,
    "forms": ["No specific forms required; consent from resident/representative for actions. Volunteering requires separate forms via state site.[3]"],
    "documents": ["No documents needed to contact or receive services; provide details of concern/complaint verbally or in writing. For formal representation, proof of resident status or representative authority may help but not required.[2][6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services for residents in Maryland's ~227 nursing homes and ~1,756 assisted living facilities.",
    "regional_variations": "Administered by State Office + 19 Local Programs at Area Agencies on Aging, each serving specific regions with trained staff/volunteers conducting visits. Contact local program for your area; examples include Howard and Montgomery Counties with dedicated contacts. No specified differences in services, but regional offices handle local facilities.[3][4][7]",
    "offices_or_providers": ["State Long-Term Care Ombudsman Program (Maryland Department of Aging).", "19 Local LTC Ombudsman Programs at Area Agencies on Aging.[3][4]"]
  },
  "official_source": "https://aging.maryland.gov/pages/state-long-term-care-ombudsman.aspx[3]",
  "gotchas": ["Not a Medicaid or financial aid program—pure advocacy only (often confused as in [1]).", "Requires resident consent for actions; Ombudsman works at resident direction, not automatically.", "Free/confidential, but independent of facilities (no conflicts of interest).", "Anyone can contact (not just residents), but prioritizes resident needs.", "For emergencies or regulatory violations, may refer to Office of Health Care Quality (OHCQ).[6][7]"],
  "data_shape_notes": "no income test; resident consent-driven advocacy; delivered via 19 regional local programs statewide; free to all in nursing homes/assisted living; not financial aid"
}
